<span class="line"><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">sudo</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> pacman-key</span><span style="--shiki-light:#A65E2B;--shiki-dark:#C99076;"> --init</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> </span></span>
